        String mergedString;
        int pointer = 0;
        // Notes : Take length of 2 strings for iteration; use pointer initialised at 0, add each character to stringbuilder as long as
        //pointer is < word

        while (word1.length() + word2.length() != pointer){ //for (int pointer= 0; pointer < (word1.length() + word2.length()); pointer++){  
            if (pointer < word1.length()){
                alternateLetters.append(word1.charAt(pointer));
            }
            if (pointer < word2.length()){
                alternateLetters.append(word2.charAt(pointer));
            }
            pointer ++;
        }
        mergedString = alternateLetters.toString();
        return mergedString;

    }
}

product-of-array-except-self_java:
class Solution {
    public int[] productExceptSelf(int[] nums) {

        int size = nums.length;
        int[] prefProduct= new int[size];
        int[] suffProduct = new int[size];
        int[] answer = new int[size];

        // Contruct the prefix products array
        prefProduct[0] = 1;
        for (int i =1; i < size; i ++){
            prefProduct[i]= prefProduct[i-1] * nums[i-1];
        }
        //construct the suffix products array
        suffProduct[size-1] = 1;
        for (int i= size-2; i >= 0; i--){
            suffProduct[i] = suffProduct[i+1] * nums[i+1];
        }
        //construct answer array using prefProduct[] * suffProduct[]
        for (int i = 0; i < size; i ++){
            answer[i]= prefProduct[i] * suffProduct[i];
        }

        return answer; 
    }
}

